+ 450         info!(
+ 451             event = "archive-patcher-execute-request",
+ 452             "Archive Patcher confirmed execution requested"
+ 453         );
+ 454 
+ 455         let plan = self.preview_plan(ArchivePatcherPlanRequest::new(
+ 456             request.request_id,
