+ 462         let plan_digest = plan.stable_digest();
+ 463         if let Some(expected_digest) = request.confirmed_plan_digest {
+ 464             if plan_digest != expected_digest {
+ 465                 warn!(
+ 466                     event = "archive-patcher-confirmed-plan-changed",
+ 467                     request_id = request.request_id,
+ 468                     expected_digest,
+ 469                     actual_digest = plan_digest.as_str(),
+ 470                     "Archive Patcher confirmed run aborted because the preview plan changed"
+ 471                 );
+ 472                 return Err(ArchivePatcherExecutionError::ConfirmedPlanChanged {
+ 473                     safe_message: CONFIRMED_ARCHIVE_PLAN_CHANGED_MESSAGE.to_owned(),
+ 474                     expected_digest: expected_digest.to_owned(),
+ 475                     actual_digest: plan_digest,
+ 476                 });
+ 477             }
