+ 494                 request_id = request.request_id,
+ 495                 entry_count = manifest.entries.len(),
+ 496                 manifest_path = %request.manifest_path.display(),
+ 497                 "Archive Patcher latest restore manifest written before mutation"
+ 498             );
+ 499         }
+ 500 
+ 501         let mut result = ArchivePatcherExecutionResult {
+ 502             request_id: request.request_id,
+ 503             target: request.target,
+ 504             manifest_path: request.manifest_path.to_path_buf(),
+ 505             plan_digest,
+ 506             rows: Vec::with_capacity(plan.rows.len()),
+ 507             log_rows: Vec::with_capacity(plan.rows.len().saturating_add(1)),
+ 508             counts: ArchivePatcherSummaryCounts::default(),
+ 509             diagnostics: Vec::new(),
+ 510         };
+ 511 
+ 512         if plan.rows.is_empty() {
+ 513             let log_row = nothing_to_do_log_row();
+ 514             result.log_rows.push(log_row);
+ 515             return Ok(result);
+ 516         }
+ 517 
+ 518         for row in &plan.rows {
+ 519             let file_result = self.execute_patch_row(request.data_root, row);
+ 520             debug!(
+ 521                 event = "archive-patcher-execute-row-complete",
+ 522                 request_id = request.request_id,
+ 523                 path = %file_result.archive_path.display(),
+ 524                 outcome = ?file_result.outcome,
+ 525                 diagnostic_count = file_result.diagnostics.len(),
+ 526                 "Archive Patcher execution row completed"
+ 527             );
+ 528             result.log_rows.push(file_result.log_row.clone());
+ 529             result.diagnostics.extend(file_result.diagnostics.clone());
+ 530             result.rows.push(file_result);
+ 531         }
+ 532 
+ 533         let patched = result
+ 534             .rows
+ 535             .iter()
+ 536             .filter(|row| row.outcome == ArchivePatcherExecutionOutcome::Patched)
+ 537             .count();
+ 538         let failed = result
+ 539             .rows
+ 540             .iter()
+ 541             .filter(|row| row.outcome == ArchivePatcherExecutionOutcome::Failed)
+ 542             .count();
+ 543         result.counts = ArchivePatcherSummaryCounts::patch(patched, failed);
+ 544         result.log_rows.push(ArchivePatcherLogRow::new(
